python3 - <<'PY'
from pathlib import Path
root=Path('awesome-codex-skills')
en_dirs={p.name for p in (root/'en/top-level').iterdir() if p.is_dir()}
zh_dirs={p.name for p in (root/'zh/top-level').iterdir() if p.is_dir()}
print('en skills', len(en_dirs), 'zh skills', len(zh_dirs))
print('missing zh dirs', sorted(en_dirs-zh_dirs))
print('extra zh dirs', sorted(zh_dirs-en_dirs))
for lang in ['en','zh']:
    files=[]
    for d in sorted((root/lang/'top-level').iterdir()):
        if d.is_dir():
            rels={p.relative_to(d).as_posix() for p in d.rglob('*') if p.is_file()}
            files.append((d.name, rels))
    bad=[]
    for name, rels in files:
        if 'SKILL.md' not in rels:
            bad.append((name,'missing SKILL.md'))
    print(lang, 'bad', bad[:10], 'count', len(bad))
print('composio leftovers', list(root.rglob('*composio-skills*'))[:5])
PY

